package main

import (
	"bufio"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type Vector struct {
	data     []int
	size     int
	capacity int
}

func NewVector(capacity int) *Vector {
	return &Vector{
		data:     make([]int, capacity), // nunca use len(data) ou cap(data) ou qq método do go de manipulação de array
		size:     0,
		capacity: capacity,
	}
}
func (v *Vector) Reserve(newCapacity int) {
	var newData []int = make([]int, newCapacity)

	v.capacity = newCapacity

	for i := range v.size {

		newData[i] = v.data[i]

	}

	v.data = newData

}
func (v *Vector) PushBack(value int) {
	if v.size == 0 {
		v.data[0] = value
		v.size++
		return
	}

	if v.size < v.capacity {
		v.data[v.size] = value
		v.size++
	} else {
		newData := make([]int, v.capacity*2)

		for i := range v.size {

			newData[i] = v.data[i]

		}

		v.capacity *= 2
		v.data = newData
		v.data[v.size] = value
		v.size++

	}

}

func (v *Vector) PopBack() error {
	if v.size == 0 {
		return errors.New("vector is empty")
	}

	v.data[v.size-1] = 0
	v.size--

	return nil
}
func (v *Vector) Status() string {
	return "size:" + strconv.Itoa(v.size) + " capacity:" + strconv.Itoa(v.capacity)
}
func (v *Vector) Show() []string {
	var s = make([]string, v.size)

	if v.size > 0 {
		for i := range v.size - 1 {

			s[i] = strconv.Itoa(v.data[i]) + ","

		}
		s[v.size-1] = strconv.Itoa(v.data[v.size-1])
	}
	return s
}

func (v *Vector) At(index int) (int, error) {
	if index < 0 || index >= v.size {
		return 0, errors.New("index out of range")
	}

	return v.data[index], nil

}

func (v *Vector) Set(index, value int) error {
	if index < 0 || index >= v.capacity {
		return errors.New("index out of range")
	}

	for i := range v.size {

		if i == index {
			v.data[i] = value
		}

	}

	return nil
}

func (v *Vector) Clear() {

	for i := range v.size {

		v.data[i] = 0

	}
	v.size = 0

}

func (v *Vector) Insert(index, value int) error {
	if index < 0 || index >= v.size {
		return errors.New("index out of range")
	}

	if v.size+1 > v.capacity {
		newData := make([]int, v.capacity*2)

		for i := range v.size {

			newData[i] = v.data[i]

		}

		v.capacity *= 2
		v.data = newData
	}

	for i := v.size; i > index; i-- {

		v.data[i] = v.data[i-1]

	}
	v.data[index] = value
	v.size++

	return nil
}

func (v *Vector) Erase(index int) error {
	if index < 0 || index >= v.size {
		return errors.New("index out of range")
	}

	for i := index; i < v.size-1; i++ {

		v.data[i] = v.data[i+1]

	}

	v.data[v.size-1] = 0
	v.size--

	return nil
}

func (v *Vector) IndexOf(value int) int {

	for i := range v.size {

		if v.data[i] == value {
			return i
		}

	}

	return -1
}
func (v *Vector) Contains(value int) bool {

	for i := range v.size {

		if v.data[i] == value {
			return true
		}

	}

	return false
}

func (v *Vector) Slice(start, end int) []string {
	if start > v.capacity {
		start = v.capacity % start
	}
	if end > v.capacity {
		end = v.capacity % end
	}

	if start < 0 {
		start += v.size
	}
	if end < 0 {
		end += v.size
	}

	slice := NewVector(end - start)

	for i := start; i < end; i++ {

		slice.PushBack(v.data[i])

	}

	return slice.Show()
}

func Join(slice []int, sep string) string {
	if len(slice) == 0 {
		return ""
	}
	var result strings.Builder
	fmt.Fprintf(&result, "%d", slice[0])
	for _, value := range slice[1:] {
		fmt.Fprintf(&result, "%s%d", sep, value)
	}
	return result.String()
}

func main() {
	var line, cmd string
	scanner := bufio.NewScanner(os.Stdin)

	v := NewVector(0)
	for {
		fmt.Print("$")
		if !scanner.Scan() {
			break
		}
		line = scanner.Text()
		fmt.Println(line)
		parts := strings.Fields(line)
		if len(parts) == 0 {
			continue
		}
		cmd = parts[0]

		switch cmd {
		case "end":
			return
		case "init":
			value, _ := strconv.Atoi(parts[1])
			v = NewVector(value)
		case "push":
			for _, part := range parts[1:] {
				value, _ := strconv.Atoi(part)
				v.PushBack(value)
			}
		case "show":
			fmt.Println(v.Show())
		case "status":
			fmt.Println(v.Status())
		case "pop":
			err := v.PopBack()
			if err != nil {
				fmt.Println(err)
			}
		case "insert":
			index, _ := strconv.Atoi(parts[1])
			value, _ := strconv.Atoi(parts[2])
			err := v.Insert(index, value)
			if err != nil {
				fmt.Println(err)
			}
		case "erase":
			index, _ := strconv.Atoi(parts[1])
			err := v.Erase(index)
			if err != nil {
				fmt.Println(err)
			}
		case "indexOf":
			value, _ := strconv.Atoi(parts[1])
			index := v.IndexOf(value)
			fmt.Println(index)
		case "contains":
			value, _ := strconv.Atoi(parts[1])
			if v.Contains(value) {
				fmt.Println("true")
			} else {
				fmt.Println("false")
			}
		case "clear":
			v.Clear()
		case "capacity":
			// fmt.Println(v.Capacity())
		case "get":
			index, _ := strconv.Atoi(parts[1])
			value, err := v.At(index)
			if err != nil {
				fmt.Println(err)
			} else {
				fmt.Println(value)
			}
		case "set":
			index, _ := strconv.Atoi(parts[1])
			value, _ := strconv.Atoi(parts[2])
			err := v.Set(index, value)
			if err != nil {
				fmt.Println(err)
			}

		case "reserve":
			newCapacity, _ := strconv.Atoi(parts[1])
			v.Reserve(newCapacity)
		case "slice":
			start, _ := strconv.Atoi(parts[1])
			end, _ := strconv.Atoi(parts[2])
			slice := v.Slice(start, end)
			fmt.Println(slice)
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
